// // This module captures the input value on the falling edge of the clock and resets the output to 1 when the reset signal is deasserted.
module DFlipFlop (
    input clk,
    input reset,
    input d,
    output reg q
);

    always @(posedge clk) begin
        if (reset)
            q <= 1'b0;
        else
            q <= d;
    end

endmodule
